texte = "bonjour le monde"
compteur = 0

for lettre in texte:
    if lettre == "e":
        compteur += 1

print(compteur)  # Affiche : 3

texte = "bonjour le monde"
compteur = 0

for caractere in texte:
    if caractere == " ":
        compteur += 1

print(compteur)  # Affiche : 2

texte = "Bonjour Le Monde"
compteur = 0

for lettre in texte:
    if lettre >= "A" and lettre <= "Z":
        compteur += 1

print(compteur)  # Affiche : 3

texte = "kayak"
est_palindrome = True

for i in range(len(texte) // 2):
    if texte[i] != texte[len(texte) - 1 - i]:
        est_palindrome = False

print(est_palindrome)  # Affiche : True

